   247|function runCurlCapture(args, label) {
   248|  return new Promise((resolve, reject) => {
   249|    const stdout = [];
   250|    const stderr = [];
   251|    const child = spawn("curl", args, { stdio: ["ignore", "pipe", "pipe"] });
   252|    const timer = setTimeout(() => {
   253|      child.kill();
   254|      reject(new Error(`${label} timed out after ${CURL_TEXT_TIMEOUT_MS / 1000}s`));
   255|    }, CURL_TEXT_TIMEOUT_MS);
   256|
   257|    child.stdout.on("data", (chunk) => stdout.push(chunk));
   258|    child.stderr.on("data", (chunk) => stderr.push(chunk));
   259|    child.on("error", (error) => {
   260|      clearTimeout(timer);
   261|      reject(error);
   262|    });
   263|    child.on("exit", (code) => {
   264|      clearTimeout(timer);
   265|      if (code === 0) {
   266|        resolve(Buffer.concat(stdout).toString("utf8"));
   267|        return;
   268|      }
   269|      const message = Buffer.concat(stderr).toString("utf8").trim();
   270|      reject(new Error(`${label} failed with curl exit code ${code}${message ? `: ${message}` : ""}`));
   271|    });
   272|  });
